changeSet.sql:
delete from AppConfigElement where appConfigElementDescriptor_id in (
    select id from AppConfigElementDescriptor where app_id = (
        select id from App where name = 'app.jove'));

delete from AppConfigElementSet where userAppConfig_id in (
    select id from UserAppConfig where app_id = (
        select id from App where name = 'app.jove'));

delete from AppConfigElementDescriptor where app_id = (
    select id from App where name = 'app.jove');

delete from UserAppConfig where app_id = (
    select id from App where name = 'app.jove');

delete from SystemPropertyValue where property_id = (
    select sp.id from SystemProperty sp
    inner join PropertyDescriptor pd on sp.descriptor_id = pd.id
    where pd.name = 'jove.available');

delete from SystemProperty where descriptor_id = (
    select id from PropertyDescriptor where name = 'jove.available');

delete from PropertyDescriptor where name = 'jove.available';
